import React, { useState, useRef } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useDispatch } from 'react-redux';
import { setCredentials } from '../store/authSlice';
import { authAPI } from '../services/api';

export default function Register() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const fileInputRef = useRef(null);

  const [form, setForm] = useState({
    name: '', email: '', password: '', phone: '', college: '', degree: '',
  });
  const [resumeFile, setResumeFile] = useState(null);
  const [dragOver, setDragOver] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [step, setStep] = useState(1);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleDrop = (e) => {
    e.preventDefault();
    setDragOver(false);
    const file = e.dataTransfer.files[0];
    if (file) setResumeFile(file);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const formData = new FormData();
      Object.entries(form).forEach(([k, v]) => v && formData.append(k, v));
      if (resumeFile) formData.append('resume', resumeFile);

      const res = await authAPI.register(formData);
      dispatch(setCredentials({ user: res.data.user, token: res.data.token }));
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="page-bg flex items-center justify-center px-4 py-24 min-h-screen">
      <div className="w-full max-w-md animate-slide-up">
        {/* Header */}
        <div className="text-center mb-8">
          <div className="w-14 h-14 rounded-2xl flex items-center justify-center mx-auto mb-4 text-2xl font-black text-white"
            style={{ background: 'linear-gradient(135deg, #7c3aed, #a855f7)' }}>
            HE
          </div>
          <h1 className="text-2xl font-bold text-white">Join HireEasy</h1>
          <p className="text-gray-400 text-sm mt-1">Upload your resume. Get matched instantly.</p>
        </div>

        <div className="glass-card p-8">
          {error && (
            <div className="mb-5 p-3.5 rounded-xl bg-red-500/10 border border-red-500/30 text-red-300 text-sm">
              ⚠️ {error}
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-4">
            {/* Step 1: Basic info */}
            <div className="grid grid-cols-2 gap-4">
              <div className="col-span-2">
                <label className="block text-xs text-gray-400 mb-1.5 font-medium">Full Name *</label>
                <input name="name" required value={form.name} onChange={handleChange}
                  className="input-field" placeholder="Dikshant Choudhary" />
              </div>
              <div className="col-span-2">
                <label className="block text-xs text-gray-400 mb-1.5 font-medium">Email *</label>
                <input name="email" type="email" required value={form.email} onChange={handleChange}
                  className="input-field" placeholder="you@example.com" />
              </div>
              <div className="col-span-2">
                <label className="block text-xs text-gray-400 mb-1.5 font-medium">Password *</label>
                <input name="password" type="password" required value={form.password} onChange={handleChange}
                  className="input-field" placeholder="Min 6 characters" minLength={6} />
              </div>
              <div>
                <label className="block text-xs text-gray-400 mb-1.5 font-medium">Phone</label>
                <input name="phone" value={form.phone} onChange={handleChange}
                  className="input-field" placeholder="+91 9876543210" />
              </div>
              <div>
                <label className="block text-xs text-gray-400 mb-1.5 font-medium">Degree/Branch</label>
                <input name="degree" value={form.degree} onChange={handleChange}
                  className="input-field" placeholder="B.Tech CSE" />
              </div>
              <div className="col-span-2">
                <label className="block text-xs text-gray-400 mb-1.5 font-medium">College/University</label>
                <input name="college" value={form.college} onChange={handleChange}
                  className="input-field" placeholder="IIT Delhi, VIT Vellore..." />
              </div>
            </div>

            {/* Resume Upload */}
            <div>
              <label className="block text-xs text-gray-400 mb-1.5 font-medium">
                Resume (PDF/DOCX) — <span className="text-purple-400">Auto-extracts your skills</span>
              </label>
              <div
                className={`drop-zone p-6 text-center ${dragOver ? 'drag-over' : ''}`}
                onDrop={handleDrop}
                onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
                onDragLeave={() => setDragOver(false)}
                onClick={() => fileInputRef.current?.click()}
              >
                {resumeFile ? (
                  <div className="flex items-center justify-center gap-3">
                    <span className="text-2xl">📄</span>
                    <div className="text-left">
                      <p className="text-white text-sm font-medium">{resumeFile.name}</p>
                      <p className="text-gray-400 text-xs">{(resumeFile.size / 1024).toFixed(0)} KB</p>
                    </div>
                    <button
                      type="button"
                      onClick={(e) => { e.stopPropagation(); setResumeFile(null); }}
                      className="text-red-400 hover:text-red-300 ml-2 text-lg"
                    >×</button>
                  </div>
                ) : (
                  <div>
                    <div className="text-3xl mb-2">📤</div>
                    <p className="text-gray-300 text-sm font-medium">Drop your resume here</p>
                    <p className="text-gray-500 text-xs mt-1">PDF, DOCX, DOC up to 5MB</p>
                  </div>
                )}
              </div>
              <input
                ref={fileInputRef}
                type="file"
                accept=".pdf,.docx,.doc,.txt"
                className="hidden"
                onChange={(e) => setResumeFile(e.target.files[0])}
              />
            </div>

            <button
              type="submit"
              disabled={loading}
              className="btn-primary w-full flex items-center justify-center gap-2 mt-2 disabled:opacity-50"
            >
              {loading ? (
                <><div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> Parsing resume...</>
              ) : (
                '🚀 Create Account & Find Opportunities'
              )}
            </button>
          </form>

          <p className="text-center text-gray-500 text-sm mt-5">
            Already have an account?{' '}
            <Link to="/login" className="text-purple-400 hover:text-purple-300 font-medium">Sign in</Link>
          </p>
        </div>
      </div>
    </div>
  );
}
